INSERT INTO creatures VALUES
('Saltwater Crocodile', 'Natural Fauna', 'Common', 'Kimberley / Northern waterways', 28, 9, 3, 13, 28, 10, 12, 13, NULL, '', '8', '', 5, 2, '', '', '', 'Amphibious / Doesn''t Breathe (2hr) / Night Vision 5 / Peripheral Vision / Silence 3 (water)', 'Cold-Blooded', '', '', '', '', '', ' failure = full bite damage + submersion', 'Running water / Cold temperatures (<15C)'),
('Eastern Brown Snake', 'Natural Fauna', 'Common', 'All eastern/northern Australia', 2, 14, 2, 12, 2, 9, 12, 12, NULL, '', '', '', 0, -2, '', '', '', 'Cold-Blooded / Vibration Detection 10m / Camouflage (Per -3 to spot)', '', '', '', '', '', '', 'Antivenin within 2 hours', 'Pressure immobilisation bandage adds +2 to all venom HT rolls. Multiple strikes possible.'),
('Inland Taipan', 'Natural Fauna', 'Common (in range)', 'Nullarbor fringe / Pilbara', 2, 15, 2, 13, 2, 9, 13, 13, NULL, '', '', '', 0, -2, '', '', '', 'Cold-Blooded / Enhanced Dodge 3 / Vibration Detection 10m / Camouflage (Per -3)', '', '', '', '', '', '', 'Taipan-specific antivenin', 'Most venomous terrestrial snake in world. Each additional bite = separate venom progression.'),
('King Brown Snake', 'Natural Fauna', 'Uncommon', 'Kimberley / Pilbara / Nullarbor', 4, 12, 2, 13, 4, 10, 12, 13, NULL, '', '', '', 0, -1, '', '', '', 'Cold-Blooded / Flattening display', '', '', '', '', '', '', 'Antivenin', 'Bites and holds — multiple venom doses. Multiple bites = multiple simultaneous progressions.'),
('Tiger Snake', 'Natural Fauna', 'Common', 'Melbourne / Snowy Mountains / Southern Australia', 3, 12, 2, 12, 3, 10, 12, 12, NULL, '', '', '', 0, -2, '', '', '', 'Cold-Blooded / Vibration Detection 8m / Flattening display', '', '', '', '', '', '', 'Antivenin', 'Primary snakebite risk in Victorian scenarios. Present along all Yarra corridor parkland.'),
('Red-Bellied Black Snake', 'Natural Fauna', 'Common', 'Eastern Australia', 3, 12, 2, 11, 3, 9, 11, 11, NULL, '', '', '', 0, -2, '', '', '', 'Cold-Blooded / Vibration Detection 8m', '', '', '', '', '', '', 'Antivenin (cross-reactive)', 'Less dangerous than brown/tiger snakes but still requires antivenin. Common near waterways.'),
('Redback Spider', 'Natural Fauna', 'Common', 'All scenarios (built environments)', 1, 13, 2, 10, 1, 9, 12, 12, NULL, '', '', '', 0, -6, '', '', '', 'Aggressive / Multiple bite capacity', '', '', '', '', '', '', 'Antivenin available', 'Use to establish Australia is always trying to kill you. Present in all station sheds / infrastructure.'),
('Funnel-Web Spider', 'Natural Fauna', 'Uncommon', 'Eastern Australia / Melbourne scenarios', 1, 13, 2, 12, 1, 11, 12, 12, NULL, '', '', '', 0, -6, '', '', '', 'Aggressive (no flight response) / Fangs penetrate fingernails / Multiple bite capacity', '', '', '', '', '', '', 'Antivenin (must reach hospital)', 'Aggressive — will stand ground. Habitat: disturbed soil near bridge footings. Melbourne bridge scenes.'),
('Blue-Ringed Octopus', 'Natural Fauna', 'Uncommon', 'Coastal rock pools — Cossack / Melbourne coast', 1, 14, 3, 11, 1, 9, 14, 11, NULL, '', '', '', 0, -5, '', '', '', 'Camouflage (passive / no roll) / Blue ring display (Per +2 when displaying) / Aquatic', '', '', '', '', '', '', 'NO antivenin exists', 'Treatment: artificial respiration maintained 4-6 hours. No antivenin. Can kill in 30 minutes.'),
('Stonefish', 'Natural Fauna', 'Uncommon', 'Coastal/reef — Cossack', 3, 8, 2, 12, 3, 9, 12, 12, NULL, '', '', '', 2, -2, '', '', '', 'Camouflage (perfect — Per -4 to spot) / Aquatic / Venomous dorsal spines', '', '', '', '', '', '', 'Antivenin / Hot water immersion (denatures venom)', 'Most venomous fish in world. Looks exactly like a rock. Common in Cossack coastal scenario.'),
('Wild Boar (Feral Pig)', 'Natural Fauna', 'Common', 'Kimberley / Pilbara / High country approaches', 16, 9, 4, 13, 16, 9, 11, 13, NULL, '', '', '', 2, 1, '', '', '', 'Acute Smell +4 / Discrimination Smell / Night Vision 3 / Peripheral Vision', '', '', '', '', '', '', '', ''),
('Dingo', 'Natural Fauna', 'Common', 'All mainland scenarios', 10, 12, 5, 12, 10, 9, 15, 12, NULL, '', '', '', 1, 0, '', '', '', 'Acute Hearing +3 / Acute Smell +4 / Night Vision 5 / Peripheral Vision / Pack Tactics (+2 when 3+ coordinate)', '', '', '', '', '', '', '', 'Unusual behaviour near spiritual sites — depart suddenly without gradual retreat. Use as omen indicator.'),
('Wedge-Tailed Eagle', 'Natural Fauna', 'Uncommon', 'All scenarios', 5, 14, 4, 12, 5, 11, 18, 12, NULL, '', '', '', 1, 0, '', '', '', 'Acute Vision +7 / Flight (Winged) / Sharp Claws and Beak', 'Cannot Fly (land)', '', '', '', '', '', '', 'Unusual attentive behaviour near significant sites — perch closer than normal comfort zone.'),
('Cassowary', 'Natural Fauna', 'Uncommon', 'Tropical north (Far North Queensland extension)', 20, 11, 4, 13, 20, 12, 13, 13, NULL, '', '', '', 2, 1, '', '', '', 'Acute Hearing +2 / Acute Smell +2 / Cannot Fly / Danger Sense / Peripheral Vision / Territorial (auto-attack within 10m of nest)', '', '', '', '', '', '', 'Running distance / Backing away slowly', 'Stand tall and back away. Running triggers pursuit at Move 8. Most dangerous bird in world by injury record.'),
('Goanna (Perentie)', 'Natural Fauna', 'Common', 'Kimberley / Nullarbor / All arid regions', 12, 10, 3, 12, 12, 9, 12, 12, NULL, '', '', '', 2, 1, '', '', '', 'Acute Smell +3 (forked tongue) / Claws / Enhanced Move 1 (sprint) / Teeth / Bacterial Load', '', '', '', '', '', '', 'Cold / Being cornered causes panic', 'Absent from gorge approaches = omen indicator. Present at all campsites due to food scavenging.'),
('Ghost Bat', 'Natural Fauna', 'Uncommon', 'Kimberley caves / Nullarbor cave systems', 1, 14, 3, 11, 1, NULL, NULL, NULL, NULL, '', '', '', 0, -4, '', '', '', '', '', '', '', '', '', '', '', 'Absent from deep Nullarbor chambers = marker of where conditions change.'),
('Common Wombat', 'Natural Fauna', 'Common', 'High country / Snowy Mountains', 14, 7, 3, 13, 14, 9, 10, 14, NULL, '', '', '', 4, 0, '', '', '', 'Absolute Direction (home range) / Burrowing / Tunnel Vision', '', '', '', '', '', '', '', 'Absent above snowgum belt / near platform = omen. Wombat burrows are ankle-trap hazard at night.'),
('Platypus', 'Natural Fauna', 'Common', 'Eastern rivers — Yarra / Snowy Mountains', 3, 11, 3, 11, 3, NULL, NULL, NULL, NULL, '', '', '', 0, -3, '', '', '', 'Aquatic', '', '', '', '', '', '', 'No antivenin', 'Hyperalgesia: all wound pain penalties increased by modifier for duration. Not life-threatening. Extremely miserable.'),
('Bull Shark', 'Natural Fauna', 'Uncommon', 'Yarra River (Melbourne) / Coastal waterways', 22, 10, 3, 12, 22, 10, 14, 12, NULL, '', '', '', 2, 1, '', '', '', 'Enhanced Move 2 (water) / No Legs (aquatic) / Bloodscent (detects blood at 400m) / Aggressive', '', '', '', '', '', '', 'Leaving the water', 'In the Yarra at 3am during bridge scenes. Not supernatural — just a bull shark in a tidal river.'),
('Magpie (Swooping)', 'Natural Fauna', 'Common', 'All scenarios — ubiquitous', 2, 14, 5, 12, 2, NULL, NULL, 12, NULL, '', '', '', NULL, '–3', '', '', '', 'Aggressive (swooping season Aug–Nov)', '', '', '', '', '', '', 'Leaving nesting territory', 'Magpies near Birrarung station do NOT swoop — watching instead. Use as atmosphere indicator.'),
('Brumby Mob (Stampede)', 'Natural Fauna', 'Uncommon', 'Snowy Mountains / High country', '30 (collective)', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', '', '2 (hide)', '+2 (mob)', '', '', '', 'Enhanced Move 2 (gallop) / Flight response / Panic transmission to herd', '', '', '', '', '', '', 'Open ground / Climbing above stampede path', 'Evasion: Dodge -2. The bay brumby with white blaze: Animal Handling -1 (slightly less reactive). Leads to the platform.'),
('The Marloo', 'Supernatural', 'Rare', 'Kimberley — ochre gorge surrounds', 18, 14, 6, 16, 24, 14, 16, 18, NULL, '', '', '', 4, '+1 to +2 (variable)', '', '', '', 'Alternate Form (any dead animal in territory) / Doesn''t Sleep / Indomitable / Night Vision 9 / Silence 4 / Terrain Adaptation / Unfazeable', '', '', '', '', '', '', 'Ochre across threshold (Will -4 to cross) / Running water / Ceremony with correct intent', 'Goal: return drill core to gorge. Herds rather than attacks. Withdraws permanently when drill core returned.'),
('Iron Presence', 'Supernatural', 'Rare', 'Ironbark Station and approaches', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', '', 'Low', 'None', '', '', '', '', '', '', '', '', '', '', '', ''),
('Stockman''s Ghost', 'Supernatural', 'Rare', 'Drysdale River Station / Melbourne (bridge scenes)', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', '', 'None', 'None', '', '', '', '', 'Points', '', '', '', '', '', 'Cannot be addressed or detained. Appears in Melbourne bridge scenes pointing toward Spencer Street.', ''),
('The Drowned Choir', 'Supernatural', 'Rare', 'Nullarbor caves — flooded lower chambers', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', '', 'None', 'Psychological', '', '', '', '', 'Sound-based lure', '', '', '', '', '', 'Not hostile. Draws players deeper into flooded sections. River Dreaming disadvantage on extended exposure.', ''),
('The Pale Rider', 'Supernatural', 'Rare', 'Snowy Mountains — high country tracks at night', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', '', 'Moderate (if on track)', 'None', '', '', '', '', 'Passes through', '', '', '', '', '', 'The ride still happening in the mountain. Passes through position — not an attack. Will always attempt to run.', ''),
('The Mimi', 'Supernatural', 'Uncommon', 'Kimberley — rocky escarpment near ochre gorge', 4, 18, 7, 14, 4, 14, 18, 14, NULL, '', '', '', 0, -1, '', '', '', 'Silence 6 / Terrain Adaptation (rock faces/crevices) / Peripheral only (Per -4 to confirm sighting) / Insubstantial / Windstill sensing', '', '', '', '', '', '', 'Wind / Direct observation (fades)', 'Always present in escarpment. Absent from deep gorge chambers = marker of significant change.'),
('Brolga Dancer', 'Supernatural Adjacent', 'Uncommon', 'Kimberley wetlands / Pilbara', 6, 12, 4, 12, 6, NULL, NULL, 12, NULL, '', '', '', 1, 'None', '', '', '', '', 'Beak strike', '', '', '', '', '', 'Not supernatural — a bird. But the pattern has been shaped by the country over generations. Equivalent information to Dora Mamid''s direct guidance.', ''),
('Willy Willy', 'Supernatural Adjacent', 'Uncommon', 'All arid scenarios', '3–8', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', '', 'Nuisance to Moderate', 'None', '', '', '', 'Debris strike', '1d-1 crush (significant) / 1d-3 (mundane)', '', '', '', '', '', '', ''),
('Cave Resonance (Embodied)', 'Supernatural', 'Rare', 'Nullarbor cave — Karra Cave deepest chamber', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', '', 'None', 'Psychological', '', '', '', '', '', '', '', '', '', '', '', ''),
('Mountain''s Regard (Direct)', 'Supernatural', 'Rare', 'Granite platform — Snowy Mountains', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', '', 'Psychological', 'None', '', '', '', '', '', '', '', '', '', '', '', ''),
('The Kurrul', 'Supernatural', 'Exclusive', 'Coastal reef off Cossack / Yarra River (conditions)', NULL, NULL, 4, NULL, NULL, NULL, 18, NULL, NULL, '', '', '', 'Extreme (psychological)', 'None', '', '', '', 'No direct attack', 'None', '', '', '', '', '', '', ''),
('Entity in the Yarra', 'Supernatural', 'Exclusive', 'Yarra River — basalt channel beneath Spencer Street Bridge', 60, NULL, 2, 30, NULL, NULL, NULL, NULL, NULL, '', '', '', NULL, 8, '', '', '', 'No Legs (Aquatic) / Doesn''t Breathe / Doesn''t Sleep / Indomitable / Unfazeable / Injury Tolerance (Diffuse) / Binding Susceptibility (-6 Move when anchor points intact) / Presence Feeding (Will <12: 1 FP/hr within 50m)', '', '', '', '', '', '', 'Acknowledgment at Spencer Street (four-part) / Bridge anchor points fully reinforced', 'Cannot be fought. Feeding is passive and indifferent. Responds only to acknowledgment — ceases pressure when registered.'),
('Nullarbor Presence', 'Supernatural', 'Exclusive', 'The entire Nullarbor Plain — concentrated in cave system', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', '', 'None', 'Psychological', '', '', '', '', '', '', '', '', '', '', '', ''),
('The Keeper', 'Supernatural', 'Rare', 'Kimberley — track between gorge and station', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', '', NULL, 'None', '', '', '', 'Speaks once then gone', '', '', '', '', '', '', 'Respect / Correct behaviour in presence', 'Appears once. Cannot be followed. Gives the one piece the players are missing. Departure: simply not present. Permanent gift: +1 Hidden Lore (Dreaming) to most attentive player.'),
('The Thing That Wears the Drowned', 'Supernatural', 'Exclusive', 'Melbourne — Last Train / last carriage (conditional)', 16, 14, 6, 14, 16, 14, 16, 14, NULL, '', '', '', 2, 0, '', '', '', 'Mimic (target loved one — Acting 18) / Detect Emotion (calibrates mimicry in real time) / Cannot cross running water', '', '', '', '', '', '', 'Direct acknowledgment of true nature / Running water / Another player''s physical intervention', 'Assembles appearance from player''s emotional residue during train ride. After-effect: see loved one''s face in crowds occasionally for rest of campaign — not the creature, just homesickness.'),
('The Administrative Appetite', 'Systemic', 'Exclusive', 'Canberra — the system itself', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', '', NULL, 'None', '', '', '', 'Death certificates / FOI reference numbers / Senate committee hearing dates', '', '', '', '', '', '', 'Naming it publicly (publication + Senate testimony) / Custodial testimony pathway', 'Not evil. Not conscious. A system with a century of practice. The most dangerous thing in the campaign.'),
('The Last Train Passengers', 'Supernatural', 'Rare', 'Melbourne — City Loop / Last Train', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', '', 'None', 'Psychological', '', '', '', '', '', '', '', '', '', '', '', ''),
('Constance Okafor (Passenger State)', 'Human NPC', 'Special', 'Melbourne — City Loop / Last Train', 9, 10, 12, 11, 9, 14, 12, 9, NULL, '', '', '', NULL, NULL, '', '', '', '', '', '', '', '', '', '', 'Not a threat. Not an enemy. A person who boarded looking for someone dead and stayed because time became confused. Must be recovered — her son is seven.', ''),
('Curious Local', 'Human NPC', 'Tier One', 'All scenarios — small towns / roadhouses', 10, 10, 10, 11, 10, 10, 12, 11, NULL, '', '', '', NULL, NULL, '', '', '', 'Contact Group (entire community skill 12 15+) / Claim to Hospitality', 'Curious / Overconfidence / Nosy', '', '', '', '', '', 'Diplomacy or Fast-Talk to redirect', 'Not malicious. Just interested. The gossip consequence is more dangerous than the person.'),
('Volunteer Searcher', 'Human NPC', 'Tier One', 'Rural / remote — missing person contexts', 11, 11, 10, 12, 11, 11, 12, 12, NULL, '', '', '', NULL, NULL, '', '', '', 'Contact (local emergency services 9+) / Fit / Claim to Hospitality', 'Sense of Duty (missing persons) / Stubbornness', '', '', '', '', '', 'Stealth vs their search pattern / Diplomacy +1 (cooperative)', 'Well-intentioned. In the way. Will report unusual activity to SES coordinator. Everything goes in their notes.'),
('Drunk at the Pub', 'Human NPC', 'Tier One', 'All pub and roadhouse encounters', 12, '7 (currently)', '9 (currently)', 13, 12, '6 (currently)', '7 (currently)', '5 (currently)', NULL, '', '', '', NULL, 'None', '', '', '', 'Alcoholism / Bully / Overconfidence / Stubbornness', 'Punch (if provoked)', '', '', '', '', '', 'Contradicting him = Reaction -2. Dismissing him = confrontation. Half embellishment half accurate legend.', ''),
('Amateur Paranormal Investigator', 'Human NPC', 'Tier One', 'All scenarios — Melbourne / Nullarbor particularly', 9, 11, 12, 10, 9, 9, 13, 10, NULL, '', '', '', NULL, NULL, '', '', '', 'Eidetic Memory (online content) / Contact (paranormal community 12+)', 'Curious / Overconfidence / Recklessness / Sense of Duty (audience)', '', '', '', '', '', 'Fast-Talk or Diplomacy to remove footage / Theft to take device', 'Thoroughly researched the location. Thermal camera detects cold spots and temperature differentials. Share research on Diplomacy +1.'),
('Journalist''s Editor', 'Human NPC', 'Tier One', 'Melbourne / Sydney', 9, 10, 14, 10, 9, 13, 14, 10, NULL, '', '', '', NULL, NULL, '', '', '', 'Contact Group (media industry skill 14 12+) / Legal Enforcement Powers (editorial)', 'Sense of Duty (publication) / Caution / Stubbornness', '', '', '', '', '', 'Provide additional documentation (each piece -1 day delay)', 'Not the enemy. The system through which the story exists. Legal department threats are standard procedure.'),
('Craig Holt', 'Human Antagonist', 'Tier Two', 'Kimberley / Melbourne (legal) / Canberra', 10, 10, 12, 11, 10, '8 (near gorge at night)', 10, 11, NULL, '', '8', '8', NULL, NULL, '', '', '', 'Legal Enforcement Powers (corporate) / Wealth (Comfortable) / Contact Group (resources industry skill 13 9+)', 'Greed / Cowardice (Will -2 when threatened) / Duty (company 15+) / Secret (no full heritage clearance) / Nightmares', '', '', '', '', '', 'Immunity offer for cooperation / Confrontation at night near gorge (Will 8)', 'Has deleted photographs from satellite communicator — recoverable on Electronics Op (Communications)-11. Does not know what is in the drill core. Afraid of it.'),
('Irene (Roadhouse Operator)', 'Human NPC', 'Tier Two', 'Nullarbor', 8, 10, 13, 11, 8, 15, 14, 11, NULL, '', '', '', NULL, NULL, '', '', '', 'Empathy / Common Sense / Contact (emergency services skill 13 12+) / Eidetic Memory (roadhouse)', 'Sense of Duty (travellers) / Nightmares / Stubborn', '', '', '', '', '', 'Respect the warning then ask about it', 'Knows one of the returning three personally — will acknowledge if pressed gently but not name them. Not a mystery — a private grief she is entitled to keep.'),
('Sandra Walgett', 'Human NPC', 'Tier Two', 'Canberra / Darwin (initially)', 9, 11, 14, 11, 9, 14, 13, 11, NULL, '', '', '', NULL, NULL, '', '', '', 'Cultural Familiarity / Contact (Walgalu community skill 14 9+) / Legal Enforcement Powers (heritage assessor — suspended) / Intuition', 'Sense of Duty (great-grandfather''s legacy) / Stubbornness / Enemy (Office of Strategic Coordination 9+) / Wealth (Struggling)', '', '', '', '', '', 'Tommy Barunga facilitation (Diplomacy +2) / David Carrick contact / Physical visit to Darwin', 'Thomas Walgett''s great-granddaughter. Went into public service specifically to recover the survey. Cannot be reached by any system-mediated communication.'),
('Private Security Contractor', 'Human Antagonist', 'Tier Two', 'Kimberley / Pilbara mining sites / Canberra', 12, 12, 10, 12, 12, 11, 12, 12, NULL, '', '9', '9', NULL, NULL, '', '', '', 'Combat Reflexes / Fit / Legal Enforcement Powers (trespass/detention)', 'Duty (company 12+) / Code of Honour (no lethal force first) / Greed (negotiable)', '', '', '', '', '', 'Diplomatic cover story (Diplomacy 0) / Knowledge of site significance (causes hesitation — Will roll or steps aside)', 'Greed modifier: +2 to negotiations if player offers financial incentive. Code of Honour: will not falsify reports or exceed authority.'),
('Detective (Investigating Players)', 'Human Antagonist', 'Tier Two', 'All scenarios — when players become visible', 11, 12, 13, 12, 11, 13, 14, 12, NULL, '', '9', '9', NULL, NULL, '', '', '', 'Legal Enforcement Powers / Intuition / Contact Group (police skill 13 12+) / Unfazeable', 'Sense of Duty (the law) / Code of Honour (police) / Stubborn', '', '', '', '', '', 'Physical evidence of supernatural that defies framework / Offering them the framework as ally', 'Turning point: player who provides undeniable evidence creates choice — file anomaly or acknowledge insufficient framework. Framework-abandoning detective = extremely powerful ally. One of the most dangerous conventional threats.'),
('Mining Site Foreman', 'Human NPC', 'Tier Two', 'Kimberley — survey site', 13, 12, 11, 13, 13, 11, 12, 13, NULL, '', '', '', NULL, NULL, '', '', '', 'Fit / Hard to Kill +2 / Danger Sense', 'Stubbornness / Duty (company 12+) / Sense of Duty (team) / Superstition (latent)', '', '', '', '', '', 'Knowledge of gorge contents / Demonstrating respect for the situation', 'Not the enemy. Has been waiting for someone to acknowledge what is happening. Checks over shoulder near drill site — habit developed last 6 weeks.'),
('Stockman with a History', 'Human NPC', 'Tier Two', 'Kimberley stations', 14, 13, 11, 14, 14, 13, 14, 14, NULL, '', '10', '10', NULL, NULL, '', '', '', 'Danger Sense / Combat Reflexes / Fit / Hard to Kill +2', 'Stubbornness / Intolerance (country disrespect) / Sense of Duty (country/custodians) / Distrust (strangers initially)', '', '', '', '', '', 'Respect-building sequence (see trust mechanic)', 'At Reaction +1 or better: most valuable Kimberley ally. Knows every track/water source/Marloo sighting last 6 months. Knows the resolution. Has been waiting for the right people.'),
('Conspiracy Theorist (Real Information)', 'Human NPC', 'Tier Two', 'All scenarios — internet / occasional physical', 8, 10, 15, 9, 8, 12, 14, 9, NULL, '', '', '', NULL, NULL, '', '', '', 'Eidetic Memory / Intuition (bureaucratic irregularity)', 'Paranoia (mild / with reason) / Curious / Reclusive / Obsession (pattern)[-10]', '', '', '', '', '', 'Matching evidence pieces from non-public sources', 'Has 3-year database of public record evidence for the pattern. Corroborates Margaret''s files and adds 3 unknown cases. Personal reason for obsession — family member is one of the unreachable.'),
('Office of Strategic Coordination Field Officer', 'Human Antagonist', 'Tier Three', 'All scenarios — when players are priority', 10, 11, 15, 11, 10, 15, 15, 11, NULL, '', '8', '', NULL, NULL, '', '', '', 'Legal Enforcement Powers (extensive) / Contact Group (Commonwealth skill 16 15+) / Intuition / Unfazeable / Empathy (as tool)', 'Duty (Office 15+) / Secret (Office existence) / Callousness', '', '', '', '', '', 'Physical confrontation (they comply completely and call superior within 1 hour — accelerates response)', 'Never engage physically. Each instance of physical intimidation adds one escalation level. Most systemically dangerous conventional human in campaign.'),
('Compromised Senior Police Officer', 'Human Antagonist', 'Tier Three', 'All scenarios — operates through authority', 11, 11, 13, 11, 11, '9 (when exposed)', 13, 11, NULL, '', '', '', NULL, NULL, '', '', '', 'Legal Enforcement Powers (senior police) / Contact Group (police skill 14 15+) / Rank / Claim to Hospitality', 'Secret (original favour) [-20] / Duty (police 15+) / Cowardice (re: exposure)[-10] / Stubbornness', '', '', '', '', '', 'Original favour evidence / Immunity negotiation pathway (Will -2 to accept / retryable once per session)', 'Redemption option: offer exposure on own terms = Will -2 roll. On success: testimony to Senate inquiry. Not irredeemably corrupt — simply protecting one wrong decision with subsequent wrong decisions.'),
('Federal Court Judge (Unnamed)', 'Human Antagonist', 'Tier Three', 'Canberra (never directly encountered)', NULL, NULL, NULL, NULL, NULL, 16, NULL, NULL, NULL, '', '15', '', NULL, 'None', '', '', '', '', 'Legal pressure (never direct)', '', '', '', '', '', 'Name in Carrick''s statement is permanent public record — sufficient', 'Never met directly. Evidence of system''s depth. Present in compendium to establish: when legal channels are attempted, this is the quality of opposition in those channels.'),
('Helen Birch', 'Human Antagonist', 'Tier Four', 'Canberra — Office of Strategic Coordination', 9, 10, 16, 10, 9, 16, 16, 10, NULL, '', '', '', NULL, NULL, '', '', '', 'Legal Enforcement Powers (maximum Commonwealth level) / Contact Group (entire Commonwealth bureaucracy skill 17 15+) / Intuition / Empathy (genuine) / Eidetic Memory / Rank (departmental secretary equivalent)', 'Duty (Office 15+) / Callousness (functional) / Secret (Office existence) / Nightmares (NT spring 2004 / every night 20 years) / Guilt (suppressed — 20pt equivalent)', '', '', '', '', '', 'Players being the people who went to the sites and came back / Complete evidence assembly / Petra Scholl''s presence', 'Not defeated — she decides. The players cannot force it. She was always going to do this eventually. They got there first. She has been to a site (NT spring 2004) and suppressed her own 38-page assessment of it.'),
('Petra Scholl', 'Human NPC', 'Tier Three', 'Canberra (Yarralumla) / Pilbara (end of campaign)', 9, 10, 13, 10, 9, 13, 13, 10, NULL, '', '', '', NULL, NULL, '', '', '', 'Hidden Lore (Dreaming)-13 / Intuition', 'Enemy (Office of Strategic Coordination 9+) / Wealth (Poor) / Administratively Dead (21 years)', '', '', '', '', '', 'David Carrick''s protection / Hidden on USB drive', 'The campaign''s most important witness. 21 years. Very tired. Wants to be alive again officially and go back to the Pilbara to see if the site still remembers her.'),
('Margaret Osei', 'Human NPC', 'Tier Two', 'Canberra — Department of PM&C (briefly) / Home', 9, 10, 14, 10, 9, 15, 14, 10, NULL, '', '', '', NULL, NULL, '', '', '', 'Contact Group (Commonwealth bureaucracy 30 years skill 14 15+) / Legal Enforcement Powers (briefly)', 'Sense of Duty (truth) / Nightmares / Stubborn', '', '', '', '', '', 'Trust built through respectful approach / Public location meeting (protection via witnesses)', '32 years of notes on the USB drive. Hidden folder contains Petra Scholl''s documents. Retirement accelerated — credentials revoked by Monday after players visit. Her fear is real and should be played as real.'),
('David Carrick', 'Human NPC', 'Tier Three', 'Canberra — Yarralumla', 9, 10, 14, 10, 9, 14, 14, 10, NULL, '', '', '', NULL, NULL, '', '', '', 'Contact Group (former Commonwealth contacts) / Eidetic Memory (the 47 cases)', 'Secret (Office involvement 20 years) / Guilt (functional — driving current choice) / Nightmares', '', '', '', '', '', 'Threat of exposure accelerates cooperation / Petra Scholl''s presence reveals full picture', 'Not redeemed — making a different choice. Was at the 1997 meeting. Signed off on Petra Scholl''s administrative death. Is sorry. That does not make it sufficient. He knows this.'),
('Billy Hanrahan', 'Human NPC', 'Tier One', 'Snowy Mountains — high country', '9 (age)', 10, 12, 10, 9, 16, 14, 10, NULL, '', '', '', NULL, NULL, '', '', '', 'Danger Sense / Unfazeable / Fit (residual)', 'Age (-3 ST/HT already applied) / Loner / Sense of Duty (the mountain)', '', '', '', '', '', 'Respectful approach — he will wait as long as needed', 'Knows where the platform is. Knows about the trade. Knows the old story before Paterson''s poem. Comes and goes without transitional states — on the rock / not on the rock. This is correct.'),
('Drysdale Station Caretaker', 'Human NPC', 'Tier One', 'Kimberley — Drysdale River Station', 10, 11, 11, 12, 10, '6 (currently)', 12, 10, NULL, '', '', '', NULL, NULL, '', '', '', '', '', '', '', '', '', '', 'Psychology or First Aid to stabilise / Physical needs (food and water)', 'Will not leave the homestead. The homestead is survivable. The outside is not. This calculation is not negotiable. Work within it.')
