CREATE TABLE IF NOT EXISTS creatures (
  Name TEXT,
  Category TEXT,
  Tier TEXT,
  Region TEXT,
  ST INTEGER,
  DX INTEGER,
  IQ INTEGER,
  HT INTEGER,
  HP INTEGER,
  Will INTEGER,
  Per INTEGER,
  FP INTEGER,
  BasicSpeed REAL,
  BasicMove TEXT,
  Dodge TEXT,
  Parry TEXT,
  DR INTEGER,
  SM INTEGER,
  PhysicalThreat TEXT,
  SystemicThreat TEXT,
  KeySkills TEXT,
  Advantages TEXT,
  Disadvantages TEXT,
  PrimaryAttack TEXT,
  AttackDamage TEXT,
  SecondaryAttack TEXT,
  SecondaryDamage TEXT,
  SpecialAbilities TEXT,
  Weakness TEXT,
  Notes TEXT
);
